function worked_http_server_ts_concurrency_backpressure_workers_4(active: number, capacity: number, queueDepth: number, tenantTokens: number): { admit: boolean; offloadCpu: boolean; reason: string } {
  if (active < 0 || capacity <= 0 || queueDepth < 0) {
    return { admit: false, offloadCpu: false, reason: "invalid-budget" };
  }
  if (tenantTokens <= 0) return { admit: false, offloadCpu: false, reason: "tenant-rate" };
